import { SlidersHorizontal } from "lucide-react";
import { PointerEvent, TouchEvent, useCallback, useEffect, useMemo, useRef, useState } from "react";
import { CanvasView, FeedStyle, Post, SortMode, User } from "../types";
import { PostCard } from "./PostCard";

type Props = {
  posts: Post[];
  users: User[];
  sortMode: SortMode;
  feedStyle: FeedStyle;
  search: string;
  view: CanvasView;
  onViewChange: (view: CanvasView) => void;
  onOpenPost: (id: string) => void;
  onOpenProfile: (id: string) => void;
  onOpenFilters: () => void;
  onLikePost: (id: string) => void;
  onRepostPost: (id: string) => void;
  onBookmarkPost: (id: string) => void;
};

const clampZoom = (zoom: number) => Math.max(0.35, Math.min(2.2, zoom));

const getStyledPosition = (post: Post, index: number, style: FeedStyle) => {
  if (style === "classic") return { x: post.x, y: post.y };
  if (style === "gallery") {
    const col = index % 5;
    const row = Math.floor(index / 5);
    const lift = post.type === "text" ? 80 : 0;
    return { x: col * 380 - 760, y: row * 350 - 220 + lift };
  }
  if (style === "orbit") {
    const ring = Math.floor(index / 8) + 1;
    const inRing = index % 8;
    const angle = (inRing / 8) * Math.PI * 2 + ring * 0.34;
    const radius = 230 + ring * 260;
    return { x: Math.cos(angle) * radius, y: Math.sin(angle) * radius };
  }
  const typeOffset = post.type === "photo" ? -360 : post.type === "video" ? 360 : 0;
  const column = index % 3;
  const row = Math.floor(index / 3);
  return { x: typeOffset + column * 80 - 80, y: row * 330 - 220 };
};

export function CanvasFeed({ posts, users, sortMode, feedStyle, search, view, onViewChange, onOpenPost, onOpenProfile, onOpenFilters, onLikePost, onRepostPost, onBookmarkPost }: Props) {
  const viewportRef = useRef<HTMLDivElement | null>(null);
  const dragRef = useRef<{ id: number; x: number; y: number; view: CanvasView } | null>(null);
  const didDragRef = useRef(false);
  const viewRef = useRef(view);
  const frameRef = useRef<number | null>(null);
  const queuedViewRef = useRef<CanvasView | null>(null);
  const [size, setSize] = useState({ width: 1400, height: 900 });
  const touchRef = useRef<{ distance: number; zoom: number } | null>(null);

  const scheduleView = useCallback((nextView: CanvasView) => {
    queuedViewRef.current = nextView;
    if (frameRef.current !== null) return;
    frameRef.current = requestAnimationFrame(() => {
      frameRef.current = null;
      const queued = queuedViewRef.current;
      if (!queued) return;
      queuedViewRef.current = null;
      viewRef.current = queued;
      onViewChange(queued);
    });
  }, [onViewChange]);

  const updateSize = useCallback(() => {
    const rect = viewportRef.current?.getBoundingClientRect();
    if (rect) setSize({ width: rect.width, height: rect.height });
  }, []);

  useEffect(() => {
    viewRef.current = view;
  }, [view]);

  useEffect(() => {
    const node = viewportRef.current;
    if (!node) return;

    const handleWheel = (event: globalThis.WheelEvent) => {
      event.preventDefault();
      updateSize();
      const current = viewRef.current;
      const rect = node.getBoundingClientRect();
      const delta = Math.max(-80, Math.min(80, event.deltaY));
      const nextZoom = clampZoom(current.zoom * (delta > 0 ? 0.93 : 1.07));
      const mx = event.clientX - rect.left;
      const my = event.clientY - rect.top;
      const worldX = (mx - current.x) / current.zoom;
      const worldY = (my - current.y) / current.zoom;
      scheduleView({ zoom: nextZoom, x: mx - worldX * nextZoom, y: my - worldY * nextZoom });
    };

    node.addEventListener("wheel", handleWheel, { passive: false });
    return () => node.removeEventListener("wheel", handleWheel);
  }, [scheduleView, updateSize]);

  const positionedPosts = useMemo(
    () => posts.map((post, index) => ({ post, position: getStyledPosition(post, index, feedStyle) })),
    [feedStyle, posts]
  );

  const visiblePosts = useMemo(() => {
    const padding = 640;
    const minX = (-view.x - padding) / view.zoom;
    const minY = (-view.y - padding) / view.zoom;
    const maxX = (size.width - view.x + padding) / view.zoom;
    const maxY = (size.height - view.y + padding) / view.zoom;
    return positionedPosts.filter(({ position }) => position.x > minX && position.x < maxX && position.y > minY && position.y < maxY);
  }, [positionedPosts, size.height, size.width, view]);

  const pointerDown = (event: PointerEvent<HTMLDivElement>) => {
    if ((event.target as HTMLElement).closest("button,input,select,textarea,a,video")) return;
    updateSize();
    didDragRef.current = false;
    dragRef.current = { id: event.pointerId, x: event.clientX, y: event.clientY, view };
    event.currentTarget.setPointerCapture(event.pointerId);
  };

  const pointerMove = (event: PointerEvent<HTMLDivElement>) => {
    const drag = dragRef.current;
    if (!drag || drag.id !== event.pointerId) return;
    if (Math.hypot(event.clientX - drag.x, event.clientY - drag.y) > 6) didDragRef.current = true;
    scheduleView({ ...viewRef.current, x: drag.view.x + event.clientX - drag.x, y: drag.view.y + event.clientY - drag.y });
  };

  const pointerUp = () => {
    dragRef.current = null;
  };

  const touchMove = (event: TouchEvent<HTMLDivElement>) => {
    if (event.touches.length !== 2) return;
    event.preventDefault();
    const [a, b] = [event.touches[0], event.touches[1]];
    const distance = Math.hypot(a.clientX - b.clientX, a.clientY - b.clientY);
    if (!touchRef.current) {
      touchRef.current = { distance, zoom: view.zoom };
      return;
    }
    scheduleView({ ...viewRef.current, zoom: clampZoom((distance / touchRef.current.distance) * touchRef.current.zoom) });
  };

  return (
    <main
      ref={viewportRef}
      className="canvas-viewport relative h-screen flex-1 cursor-grab overflow-hidden bg-[#f7f7f4] text-slate-950 active:cursor-grabbing dark:bg-[#0e1116] dark:text-white"
      onPointerDown={pointerDown}
      onPointerMove={pointerMove}
      onPointerUp={pointerUp}
      onPointerCancel={pointerUp}
      onTouchMove={touchMove}
      onTouchEnd={() => (touchRef.current = null)}
      onClickCapture={(event) => {
        if (!didDragRef.current) return;
        event.stopPropagation();
        didDragRef.current = false;
      }}
    >
      <div className="canvas-dots absolute inset-0" style={{ backgroundPosition: `${view.x}px ${view.y}px`, backgroundSize: `${24 * view.zoom}px ${24 * view.zoom}px` }} />
      <div className="pointer-events-none absolute left-4 top-4 z-20 rounded-2xl border border-slate-200 bg-white/86 px-4 py-3 shadow-glass backdrop-blur-xl dark:border-white/10 dark:bg-slate-950/86 lg:left-6">
        <p className="text-sm font-bold">Canvas</p>
        <p className="text-xs text-slate-500">{visiblePosts.length} visible · {feedStyle} · {sortMode} · {search || "all posts"}</p>
      </div>
      <button onClick={onOpenFilters} className="absolute right-4 top-4 z-20 grid h-11 w-11 place-items-center rounded-2xl border border-slate-200 bg-white/86 shadow-glass backdrop-blur-xl dark:border-white/10 dark:bg-slate-950/86 lg:hidden" aria-label="Open filters">
        <SlidersHorizontal size={19} />
      </button>
      <div className="canvas-layer absolute left-0 top-0" style={{ transform: `translate3d(${view.x}px, ${view.y}px, 0) scale(${view.zoom})` }}>
        {visiblePosts.map(({ post, position }) => {
          const author = users.find((user) => user.id === post.authorId)!;
          const emphasized = sortMode === "trending" || sortMode.startsWith("most");
          return (
            <div key={post.id} className="absolute will-change-transform" style={{ transform: `translate3d(${position.x}px, ${position.y}px, 0)` }}>
              <PostCard
                post={post}
                author={author}
                emphasized={emphasized}
                onOpen={() => onOpenPost(post.id)}
                onProfile={() => onOpenProfile(author.id)}
                onLike={() => onLikePost(post.id)}
                onComment={() => onOpenPost(post.id)}
                onRepost={() => onRepostPost(post.id)}
                onBookmark={() => onBookmarkPost(post.id)}
              />
            </div>
          );
        })}
      </div>
    </main>
  );
}

import { Image, Send, Upload, Video } from "lucide-react";
import { FormEvent, useEffect, useMemo, useState } from "react";
import { PostType, User } from "../types";

type Props = {
  open: boolean;
  currentUser: User;
  onClose: () => void;
  onPublish: (draft: { type: PostType; content: string; caption: string; imageUrl?: string; videoUrl?: string; thumbnailUrl?: string; mediaFile?: File; thumbnailFile?: File }) => void | Promise<unknown>;
};

export function Composer({ open, currentUser, onClose, onPublish }: Props) {
  const [type, setType] = useState<PostType>("text");
  const [content, setContent] = useState("");
  const [caption, setCaption] = useState("");
  const [imageUrl, setImageUrl] = useState("");
  const [videoUrl, setVideoUrl] = useState("");
  const [thumbnailUrl, setThumbnailUrl] = useState("");
  const [mediaFile, setMediaFile] = useState<File | undefined>();
  const [thumbnailFile, setThumbnailFile] = useState<File | undefined>();
  const [mediaPreview, setMediaPreview] = useState("");
  const [thumbnailPreview, setThumbnailPreview] = useState("");
  const [publishing, setPublishing] = useState(false);
  const [error, setError] = useState("");

  const preview = useMemo(() => (type === "text" ? content : caption), [caption, content, type]);
  const hasMedia = type === "photo" ? Boolean(mediaFile || imageUrl.trim()) : type === "video" ? Boolean(mediaFile || videoUrl.trim()) : true;
  const canPublish = type === "text" ? Boolean(content.trim()) : hasMedia;

  useEffect(() => {
    if (!mediaFile) {
      setMediaPreview("");
      return;
    }
    const url = URL.createObjectURL(mediaFile);
    setMediaPreview(url);
    return () => URL.revokeObjectURL(url);
  }, [mediaFile]);

  useEffect(() => {
    if (!thumbnailFile) {
      setThumbnailPreview("");
      return;
    }
    const url = URL.createObjectURL(thumbnailFile);
    setThumbnailPreview(url);
    return () => URL.revokeObjectURL(url);
  }, [thumbnailFile]);

  if (!open) return null;

  const publish = async (event: FormEvent) => {
    event.preventDefault();
    if (!canPublish || publishing) return;
    try {
      setPublishing(true);
      setError("");
      await onPublish({
        type,
        content,
        caption,
        imageUrl: type === "photo" ? imageUrl.trim() : undefined,
        videoUrl: type === "video" ? videoUrl.trim() : undefined,
        thumbnailUrl: type === "video" ? thumbnailUrl.trim() : undefined,
        mediaFile,
        thumbnailFile
      });
      setContent("");
      setCaption("");
      setImageUrl("");
      setVideoUrl("");
      setThumbnailUrl("");
      setMediaFile(undefined);
      setThumbnailFile(undefined);
      onClose();
    } catch (publishError) {
      setError(publishError instanceof Error ? publishError.message : "Could not publish this post. Please try again.");
    } finally {
      setPublishing(false);
    }
  };

  return (
    <div className="fixed inset-0 z-50 grid place-items-end bg-slate-950/35 p-0 backdrop-blur-sm sm:place-items-center sm:p-4">
      <form onSubmit={publish} className="max-h-[92vh] w-full max-w-2xl overflow-y-auto rounded-t-3xl border border-slate-200 bg-white p-5 shadow-2xl dark:border-white/10 dark:bg-slate-950 sm:rounded-3xl">
        <div className="mb-5 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <img className="h-11 w-11 rounded-full object-cover" src={currentUser.avatarUrl} alt="" />
            <div>
              <p className="font-semibold text-slate-950 dark:text-white">Create post</p>
              <p className="text-sm text-slate-500">@{currentUser.username}</p>
            </div>
          </div>
          <button type="button" onClick={onClose} className="rounded-xl px-3 py-2 text-sm font-medium hover:bg-slate-100 dark:hover:bg-white/10">
            Close
          </button>
        </div>

        <div className="mb-4 grid grid-cols-3 gap-2 rounded-2xl bg-slate-100 p-1 dark:bg-white/10">
          {(["text", "photo", "video"] as PostType[]).map((option) => (
            <button
              key={option}
              type="button"
              onClick={() => setType(option)}
              className={`flex items-center justify-center gap-2 rounded-xl px-3 py-2 text-sm font-semibold capitalize ${
                type === option ? "bg-white shadow-sm dark:bg-slate-900" : "text-slate-500"
              }`}
            >
              {option === "photo" ? <Image size={16} /> : option === "video" ? <Video size={16} /> : null}
              {option}
            </button>
          ))}
        </div>

        {type === "text" ? (
          <textarea
            value={content}
            onChange={(event) => setContent(event.target.value)}
            className="min-h-36 w-full resize-none rounded-2xl border border-slate-200 bg-transparent p-4 outline-none focus:border-teal-500 dark:border-white/10"
            placeholder="What should this canvas remember?"
          />
        ) : (
          <div className="space-y-3">
            <textarea
              value={caption}
              onChange={(event) => setCaption(event.target.value)}
              className="min-h-28 w-full resize-none rounded-2xl border border-slate-200 bg-transparent p-4 outline-none focus:border-teal-500 dark:border-white/10"
              placeholder="Write a caption..."
            />
            <input
              value={type === "photo" ? imageUrl : videoUrl}
              onChange={(event) => (type === "photo" ? setImageUrl(event.target.value) : setVideoUrl(event.target.value))}
              className="w-full rounded-xl border border-slate-200 bg-transparent px-3 py-2 text-sm outline-none focus:border-teal-500 dark:border-white/10"
              placeholder={type === "photo" ? "Paste image URL or choose a photo" : "Paste video URL or choose a video"}
            />
            <label className="flex cursor-pointer items-center justify-center gap-2 rounded-xl border border-dashed border-slate-300 px-3 py-3 text-sm font-semibold text-slate-600 hover:border-teal-500 hover:text-teal-700 dark:border-white/15 dark:text-slate-300 dark:hover:text-teal-200">
              <Upload size={17} />
              {type === "photo" ? "Choose photo from library" : "Choose video from library"}
              <input
                className="sr-only"
                type="file"
                accept={type === "photo" ? "image/*" : "video/*"}
                onChange={(event) => setMediaFile(event.target.files?.[0])}
              />
            </label>
            {type === "video" ? (
              <>
                <input
                  value={thumbnailUrl}
                  onChange={(event) => setThumbnailUrl(event.target.value)}
                  className="w-full rounded-xl border border-slate-200 bg-transparent px-3 py-2 text-sm outline-none focus:border-teal-500 dark:border-white/10"
                  placeholder="Thumbnail URL"
                />
                <label className="flex cursor-pointer items-center justify-center gap-2 rounded-xl border border-dashed border-slate-300 px-3 py-3 text-sm font-semibold text-slate-600 hover:border-teal-500 hover:text-teal-700 dark:border-white/15 dark:text-slate-300 dark:hover:text-teal-200">
                  <Upload size={17} />
                  Choose thumbnail from library
                  <input className="sr-only" type="file" accept="image/*" onChange={(event) => setThumbnailFile(event.target.files?.[0])} />
                </label>
              </>
            ) : null}
          </div>
        )}

        <div className="mt-5 overflow-hidden rounded-2xl border border-slate-200 dark:border-white/10">
          {type === "photo" && (mediaPreview || imageUrl) ? <img className="max-h-[420px] w-full bg-slate-100 object-contain dark:bg-black" src={mediaPreview || imageUrl} alt="" /> : null}
          {type === "video" && mediaPreview ? <video className="max-h-[420px] w-full bg-black object-contain" src={mediaPreview} controls /> : null}
          {type === "video" && !mediaPreview && videoUrl ? <video className="max-h-[420px] w-full bg-black object-contain" src={videoUrl} poster={thumbnailPreview || thumbnailUrl} controls /> : null}
          {type === "video" && !mediaPreview && !videoUrl && (thumbnailPreview || thumbnailUrl) ? <img className="max-h-[420px] w-full bg-slate-100 object-contain dark:bg-black" src={thumbnailPreview || thumbnailUrl} alt="" /> : null}
          <div className="p-4">
            <p className="mb-1 text-xs font-semibold uppercase text-slate-400">Draft preview</p>
            <p className="min-h-8 text-sm text-slate-700 dark:text-slate-200">{preview || (type === "text" ? "Your post preview will appear here." : "Media posts can publish with or without a caption.")}</p>
          </div>
        </div>

        {error ? <p className="mt-4 rounded-2xl bg-rose-50 p-3 text-sm font-medium text-rose-700 dark:bg-rose-400/10 dark:text-rose-200">{error}</p> : null}
        <button type="submit" className="mt-5 flex w-full items-center justify-center gap-2 rounded-2xl bg-slate-950 px-4 py-3 font-semibold text-white disabled:opacity-50 dark:bg-white dark:text-slate-950" disabled={!canPublish || publishing}>
          <Send size={18} />
          {publishing ? "Publishing..." : "Publish to canvas"}
        </button>
      </form>
    </div>
  );
}

