import { Bookmark, Heart, MessageCircle, Repeat2, Video } from "lucide-react";
import { MouseEvent } from "react";
import { Post, User } from "../types";
import { formatCount } from "../utils/posts";

type Props = {
  post: Post;
  author: User;
  emphasized?: boolean;
  onOpen: () => void;
  onProfile: () => void;
  onLike: () => void;
  onComment: () => void;
  onRepost: () => void;
  onBookmark: () => void;
};

export function PostCard({ post, author, emphasized, onOpen, onProfile, onLike, onComment, onRepost, onBookmark }: Props) {
  const text = post.type === "text" ? post.content : post.caption;
  const action = (handler: () => void) => (event: MouseEvent<HTMLButtonElement>) => {
    event.stopPropagation();
    handler();
  };

  return (
    <article
      className={`w-[320px] overflow-hidden rounded-2xl border bg-white/88 text-slate-950 shadow-glass backdrop-blur transition duration-200 hover:-translate-y-1 hover:shadow-2xl dark:border-white/10 dark:bg-slate-950/86 dark:text-slate-50 ${
        emphasized ? "ring-2 ring-teal-400" : "border-slate-200"
      }`}
      onClick={onOpen}
    >
      <div className="flex items-center gap-3 border-b border-slate-200/70 px-4 py-3 dark:border-white/10">
        <button
          className="shrink-0"
          onClick={(event) => {
            event.stopPropagation();
            onProfile();
          }}
          aria-label={`Open ${author.displayName}'s profile`}
        >
          <img className="h-10 w-10 rounded-full object-cover" src={author.avatarUrl} alt="" />
        </button>
        <div className="min-w-0">
          <p className="truncate text-sm font-semibold">{author.displayName}</p>
          <p className="truncate text-xs text-slate-500 dark:text-slate-400">@{author.username}</p>
        </div>
        <span className="ml-auto rounded-full bg-slate-100 px-2 py-1 text-[11px] font-medium uppercase text-slate-600 dark:bg-white/10 dark:text-slate-300">
          {post.type}
        </span>
      </div>

      {post.type === "photo" && post.imageUrl ? <img className="max-h-72 w-full bg-slate-100 object-contain dark:bg-black" src={post.imageUrl} alt="" loading="lazy" /> : null}
      {post.type === "video" && (post.thumbnailUrl || post.videoUrl) ? (
        <div className="relative max-h-72 bg-black">
          {post.thumbnailUrl ? (
            <img className="max-h-72 w-full object-contain" src={post.thumbnailUrl} alt="" loading="lazy" />
          ) : (
            <video className="max-h-72 w-full object-contain" src={post.videoUrl} muted preload="metadata" />
          )}
          <div className="absolute inset-0 grid place-items-center bg-black/20">
            <span className="grid h-12 w-12 place-items-center rounded-full bg-white/90 text-slate-950">
              <Video size={22} />
            </span>
          </div>
        </div>
      ) : null}

      <div className="space-y-3 p-4">
        <p className="line-clamp-5 text-sm leading-6 text-slate-700 dark:text-slate-200">{text}</p>
        <div className="flex flex-wrap gap-1">
          {post.hashtags.map((tag) => (
            <span key={tag} className="text-xs font-medium text-teal-700 dark:text-teal-300">
              #{tag}
            </span>
          ))}
        </div>
        <div className="flex items-center justify-between text-xs text-slate-500 dark:text-slate-400">
          <button onClick={action(onLike)} className="flex items-center gap-1 rounded-lg px-2 py-1 hover:bg-rose-50 hover:text-rose-600 dark:hover:bg-rose-400/10" aria-label="Like post">
            <Heart size={14} /> {formatCount(post.likesCount)}
          </button>
          <button onClick={action(onComment)} className="flex items-center gap-1 rounded-lg px-2 py-1 hover:bg-sky-50 hover:text-sky-600 dark:hover:bg-sky-400/10" aria-label="Comment on post">
            <MessageCircle size={14} /> {formatCount(post.commentsCount)}
          </button>
          <button onClick={action(onRepost)} className="flex items-center gap-1 rounded-lg px-2 py-1 hover:bg-emerald-50 hover:text-emerald-600 dark:hover:bg-emerald-400/10" aria-label="Repost">
            <Repeat2 size={14} /> {formatCount(post.repostsCount)}
          </button>
          <button onClick={action(onBookmark)} className="flex items-center gap-1 rounded-lg px-2 py-1 hover:bg-amber-50 hover:text-amber-600 dark:hover:bg-amber-400/10" aria-label="Bookmark post">
            <Bookmark size={14} /> {formatCount(post.bookmarksCount)}
          </button>
        </div>
      </div>
    </article>
  );
}

import { Bookmark, Heart, Link, MessageCircle, Repeat2, Share2, X } from "lucide-react";
import { FormEvent, useState } from "react";
import { Comment, Post, User } from "../types";
import { formatCount, formatDate } from "../utils/posts";

type Props = {
  post?: Post;
  author?: User;
  currentUser: User;
  comments: Comment[];
  users: User[];
  onClose: () => void;
  onLike: () => void;
  onRepost: () => void;
  onBookmark: () => void;
  onComment: (content: string) => void;
};

export function PostModal({ post, author, currentUser, comments, users, onClose, onLike, onRepost, onBookmark, onComment }: Props) {
  const [comment, setComment] = useState("");
  if (!post || !author) return null;
  const text = post.type === "text" ? post.content : post.caption;

  const submit = (event: FormEvent) => {
    event.preventDefault();
    if (!comment.trim()) return;
    onComment(comment);
    setComment("");
  };

  return (
    <div className="fixed inset-0 z-50 grid place-items-end bg-slate-950/45 p-0 backdrop-blur-sm sm:place-items-center sm:p-4">
      <section className="thin-scrollbar max-h-[94vh] w-full max-w-4xl overflow-y-auto rounded-t-3xl bg-white shadow-2xl dark:bg-slate-950 sm:rounded-3xl">
        <header className="sticky top-0 z-10 flex items-center justify-between border-b border-slate-200 bg-white/90 px-5 py-4 backdrop-blur dark:border-white/10 dark:bg-slate-950/90">
          <div className="flex items-center gap-3">
            <img className="h-11 w-11 rounded-full object-cover" src={author.avatarUrl} alt="" />
            <div>
              <p className="font-semibold text-slate-950 dark:text-white">{author.displayName}</p>
              <p className="text-sm text-slate-500">@{author.username} · {formatDate(post.createdAt)}</p>
            </div>
          </div>
          <button onClick={onClose} className="grid h-10 w-10 place-items-center rounded-xl hover:bg-slate-100 dark:hover:bg-white/10" aria-label="Close post">
            <X size={20} />
          </button>
        </header>

        {post.type === "photo" && post.imageUrl ? <img className="max-h-[62vh] w-full object-contain bg-slate-100 dark:bg-black" src={post.imageUrl} alt="" /> : null}
        {post.type === "video" && post.videoUrl ? <video className="max-h-[62vh] w-full bg-black" src={post.videoUrl} poster={post.thumbnailUrl} controls /> : null}

        <div className="grid gap-6 p-5 lg:grid-cols-[1fr_320px]">
          <div>
            <p className="whitespace-pre-wrap text-lg leading-8 text-slate-800 dark:text-slate-100">{text}</p>
            <div className="mt-4 flex flex-wrap gap-2">
              {post.hashtags.map((tag) => (
                <span key={tag} className="rounded-full bg-teal-50 px-3 py-1 text-sm font-medium text-teal-700 dark:bg-teal-400/10 dark:text-teal-200">
                  #{tag}
                </span>
              ))}
            </div>
            <div className="mt-6 grid grid-cols-5 gap-2">
              <button onClick={onLike} className="rounded-xl border border-slate-200 p-3 hover:bg-rose-50 dark:border-white/10 dark:hover:bg-rose-400/10">
                <Heart className="mx-auto mb-1" size={18} /> <span className="text-xs">{formatCount(post.likesCount)}</span>
              </button>
              <button className="rounded-xl border border-slate-200 p-3 dark:border-white/10">
                <MessageCircle className="mx-auto mb-1" size={18} /> <span className="text-xs">{formatCount(post.commentsCount)}</span>
              </button>
              <button onClick={onRepost} className="rounded-xl border border-slate-200 p-3 hover:bg-emerald-50 dark:border-white/10 dark:hover:bg-emerald-400/10">
                <Repeat2 className="mx-auto mb-1" size={18} /> <span className="text-xs">{formatCount(post.repostsCount)}</span>
              </button>
              <button onClick={onBookmark} className="rounded-xl border border-slate-200 p-3 hover:bg-amber-50 dark:border-white/10 dark:hover:bg-amber-400/10">
                <Bookmark className="mx-auto mb-1" size={18} /> <span className="text-xs">{formatCount(post.bookmarksCount)}</span>
              </button>
              <button className="rounded-xl border border-slate-200 p-3 dark:border-white/10">
                <Share2 className="mx-auto mb-1" size={18} /> <span className="text-xs">Share</span>
              </button>
            </div>
          </div>
          <aside>
            <form onSubmit={submit} className="mb-4 rounded-2xl border border-slate-200 p-3 dark:border-white/10">
              <div className="mb-3 flex items-center gap-2">
                <img className="h-8 w-8 rounded-full object-cover" src={currentUser.avatarUrl} alt="" />
                <span className="text-sm font-medium">@{currentUser.username}</span>
              </div>
              <textarea value={comment} onChange={(event) => setComment(event.target.value)} className="min-h-20 w-full resize-none bg-transparent text-sm outline-none" placeholder="Add a comment..." />
              <button className="mt-2 rounded-xl bg-slate-950 px-3 py-2 text-sm font-semibold text-white disabled:opacity-50 dark:bg-white dark:text-slate-950" disabled={!comment.trim()}>
                Comment
              </button>
            </form>
            <div className="space-y-3">
              {comments.map((item) => {
                const user = users.find((candidate) => candidate.id === item.authorId);
                return (
                  <div key={item.id} className="rounded-2xl bg-slate-100 p-3 dark:bg-white/10">
                    <p className="text-xs font-semibold text-slate-500">@{user?.username}</p>
                    <p className="text-sm">{item.content}</p>
                  </div>
                );
              })}
              <button className="flex items-center gap-2 text-sm font-medium text-slate-500">
                <Link size={15} /> Copy post link
              </button>
            </div>
          </aside>
        </div>
      </section>
    </div>
  );
}

import { CalendarDays, Link as LinkIcon, MapPin, X } from "lucide-react";
import { Post, PostReaction, User } from "../types";
import { formatCount, formatDate } from "../utils/posts";
import { PostCard } from "./PostCard";

type Props = {
  user?: User;
  users: User[];
  posts: Post[];
  reactions: PostReaction[];
  onClose: () => void;
  onOpenPost: (id: string) => void;
};

export function ProfileView({ user, users, posts, reactions, onClose, onOpenPost }: Props) {
  if (!user) return null;
  const repostedIds = new Set(reactions.filter((reaction) => reaction.userId === user.id && reaction.type === "repost").map((reaction) => reaction.postId));
  const userPosts = posts.filter((post) => post.authorId === user.id || repostedIds.has(post.id));
  const mediaPosts = userPosts.filter((post) => post.type !== "text");
  const pinned = userPosts.find((post) => post.pinned);

  return (
    <div className="fixed inset-0 z-50 overflow-y-auto bg-white text-slate-950 dark:bg-slate-950 dark:text-white">
      <header className="sticky top-0 z-10 flex items-center justify-between border-b border-slate-200 bg-white/88 px-4 py-3 backdrop-blur dark:border-white/10 dark:bg-slate-950/88">
        <div>
          <p className="font-bold">{user.displayName}</p>
          <p className="text-sm text-slate-500">{userPosts.length} posts</p>
        </div>
        <button onClick={onClose} className="grid h-10 w-10 place-items-center rounded-xl hover:bg-slate-100 dark:hover:bg-white/10" aria-label="Close profile">
          <X size={20} />
        </button>
      </header>
      <div className="mx-auto max-w-6xl pb-24">
        <div className="relative z-0 h-48 overflow-hidden sm:h-64">
          <img className="h-full w-full object-cover" src={user.bannerUrl} alt="" />
        </div>
        <section className="relative z-10 px-4 pb-6">
          <div className="-mt-14 flex flex-wrap items-end justify-between gap-4">
            <img className="relative z-20 h-28 w-28 rounded-full border-4 border-white bg-white object-cover shadow-xl dark:border-slate-950 dark:bg-slate-950" src={user.avatarUrl} alt="" />
            <button className="rounded-full bg-slate-950 px-5 py-2 text-sm font-bold text-white dark:bg-white dark:text-slate-950">Follow</button>
          </div>
          <div className="mt-4">
            <h1 className="text-2xl font-black">{user.displayName}</h1>
            <p className="text-slate-500">@{user.username}</p>
            <p className="mt-3 max-w-2xl leading-7 text-slate-700 dark:text-slate-200">{user.bio}</p>
            <div className="mt-3 flex flex-wrap gap-x-5 gap-y-2 text-sm text-slate-500">
              <span className="flex items-center gap-1"><MapPin size={16} /> {user.location}</span>
              <span className="flex items-center gap-1"><LinkIcon size={16} /> {user.website}</span>
              <span className="flex items-center gap-1"><CalendarDays size={16} /> Joined {formatDate(user.createdAt)}</span>
            </div>
            <div className="mt-3 flex gap-5 text-sm">
              <span><b>{formatCount(user.followingCount)}</b> Following</span>
              <span><b>{formatCount(user.followersCount)}</b> Followers</span>
            </div>
          </div>
        </section>

        <div className="grid grid-cols-4 border-y border-slate-200 text-center text-sm font-semibold dark:border-white/10">
          {["Posts", "Replies", "Media", "Likes"].map((tab) => (
            <button key={tab} className="px-3 py-4 hover:bg-slate-100 dark:hover:bg-white/10">{tab}</button>
          ))}
        </div>

        {pinned ? (
          <section className="px-4 py-6">
            <p className="mb-3 text-xs font-bold uppercase text-slate-400">Pinned post</p>
            <PostCard
              post={pinned}
              author={user}
              emphasized
              onOpen={() => onOpenPost(pinned.id)}
              onProfile={() => undefined}
              onLike={() => undefined}
              onComment={() => onOpenPost(pinned.id)}
              onRepost={() => undefined}
              onBookmark={() => undefined}
            />
          </section>
        ) : null}

        <section className="grid gap-6 px-4 py-6 lg:grid-cols-[1fr_360px]">
          <div>
            <h2 className="mb-3 text-sm font-bold uppercase text-slate-400">Status feed</h2>
            <div className="grid gap-4 sm:grid-cols-2">
              {userPosts.map((post) => (
                <div key={post.id} className="space-y-2">
                  {post.authorId !== user.id ? <p className="text-xs font-bold uppercase text-emerald-600 dark:text-emerald-300">Reposted by @{user.username}</p> : null}
                  <PostCard
                    post={post}
                    author={users.find((candidate) => candidate.id === post.authorId) || user}
                    onOpen={() => onOpenPost(post.id)}
                    onProfile={() => undefined}
                    onLike={() => undefined}
                    onComment={() => onOpenPost(post.id)}
                    onRepost={() => undefined}
                    onBookmark={() => undefined}
                  />
                </div>
              ))}
            </div>
          </div>
          <aside>
            <h2 className="mb-3 text-sm font-bold uppercase text-slate-400">Media grid</h2>
            <div className="grid grid-cols-2 gap-2">
              {mediaPosts.map((post) => (
                <button key={post.id} onClick={() => onOpenPost(post.id)} className="aspect-square overflow-hidden rounded-xl bg-slate-100 dark:bg-white/10">
                  <img className="h-full w-full object-cover" src={post.imageUrl || post.thumbnailUrl} alt="" />
                </button>
              ))}
            </div>
            <h2 className="mb-3 mt-6 text-sm font-bold uppercase text-slate-400">Following nearby</h2>
            <div className="space-y-3">
              {users.filter((candidate) => candidate.id !== user.id).map((candidate) => (
                <div key={candidate.id} className="flex items-center gap-3 rounded-2xl bg-slate-100 p-3 dark:bg-white/10">
